// Public-facing Worker (index.js)
addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  const url = new URL(request.url)
  const workerName = url.pathname.split('/')[1]

  if (!workerName) {
    return new Response('No worker specified', { status: 400 })
  }

  try {
    // Forward request to the appropriate internal worker
    const response = await fetch(`https://${workerName}.example.workers.dev${url.pathname.slice(workerName.length + 1)}`, {
      method: request.method,
      headers: request.headers,
      body: request.body
    })

    return response
  } catch (error) {
    console.error('Error forwarding request to internal worker:', error)
    return new Response('Internal Server Error', { status: 500 })
  }
}

// Internal Worker Example (worker1.js)
addEventListener('fetch', event => {
  event.respondWith(handleRequest(event.request))
})

async function handleRequest(request) {
  // Process the request
  const body = await request.text()
  return new Response(`Processed by worker1: ${body}`, { headers: { 'Content-Type': 'text/plain' } })
}

